algo_dsl_code:
// Algo runtime provides: mbd (StudioV1), polymarketWallet (string)
mbd.forUser('polymarket-wallets', polymarketWallet);

// 1. Search: Top markets by volume with strong liquidity
const searchResults = await mbd.search()
  .index('polymarket-items')
  .size(200)
  .includeVectors(true)
  .include()
    .numeric('liquidity_num', '>=', 50000)
    .numeric('volume_24hr', '>=', 25000)
  .exclude()
    .term('closed', true)
    .term('archived', true)
    .term('price_0_or_1', true)
  .sortBy('volume_24hr', 'desc')
  .execute();

mbd.addCandidates(searchResults);
mbd.log('Found ' + searchResults.length + ' popular high-volume markets');

// 2. Features: Enrich with user-item signals
const featuresResult = await mbd.features('v1').execute();
mbd.addFeatures(featuresResult);

// 3. Scoring: ML reranking
const scoringResult = await mbd.scoring()
  .model('/scoring/ranking_model/polymarket-rerank-v1')
  .execute();
mbd.addScores(scoringResult, 'rerank_score');

// 4. Ranking: Lean on rerank score + aggressive diversity
const rankingResult = await mbd.ranking()
  .sortingMethod('mix')
  .mix('topic_score', 'desc', 0.3)
  .mix('user_affinity_score', 'desc', 0.3)
  .mix('rerank_score', 'desc', 0.4)
  .diversity('semantic')
  .lambda(0.3)
  .limitByField()
  .every(10)
  .limit('ai_labels_med', 2)
  .execute();
mbd.addRanking(rankingResult);

mbd.show(mbd.getFeed());

curl_example:
curl -X POST https://api.mbd.xyz/v3/studio/search/filter_and_sort \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer mbd-YOUR_API_KEY" \
  -d '{
    "index": "polymarket-items",
    "size": 200,
    "sort_by": { "field": "volume_24hr", "order": "desc" },
    "include": [
      { "filter": "numeric", "field": "liquidity_num", "operator": ">=", "value": 50000 },
      { "filter": "numeric", "field": "volume_24hr", "operator": ">=", "value": 25000 }
    ],
    "exclude": [
      { "filter": "term", "field": "closed", "value": true },
      { "filter": "term", "field": "archived", "value": true },
      { "filter": "term", "field": "price_0_or_1", "value": true }
    ],
    "select_fields": ["question", "liquidity_num", "volume_24hr", "volume_num", "last_trade_price", "spread", "tags"]
  }'
